#include <iostream>
#include <string>

using namespace std;

class Solution {
public:
    string solve(string s) {
        string result;
        for (char c : s) if (result.empty() || result.back() != c) result += c;
        return result;
    }
};

int main() {
    Solution solution;
    string s;
    cin >> s;
    cout << solution.solve(s);
    return 0;
}
